mapper.select:
SELECT ROUND(
                       (
                           SELECT COUNT(1)
                           FROM xm_answer_report_item i
                           WHERE i.question_id = #{questionId}
                             AND i.answer_type = 1
                       ) / (
                           SELECT COUNT(1)
                           FROM xm_answer_report_item i
                           WHERE i.question_id = #{questionId}
                             AND i.answer_type != 0
                       ) * 100, 2)
